import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testValueOf_knownFormats() {
        // Test known predefined formats by name using Predefined enum
        CSVFormat defaultFormat = CSVFormat.valueOf("Default");
        assertNotNull(defaultFormat);
        assertEquals(CSVFormat.DEFAULT.getDelimiter(), defaultFormat.getDelimiter());

        CSVFormat excelFormat = CSVFormat.valueOf("Excel");
        assertNotNull(excelFormat);
        assertEquals(CSVFormat.EXCEL.getDelimiter(), excelFormat.getDelimiter());

        CSVFormat rfc4180Format = CSVFormat.valueOf("RFC4180");
        assertNotNull(rfc4180Format);
        assertEquals(CSVFormat.RFC4180.getDelimiter(), rfc4180Format.getDelimiter());

        CSVFormat tdfFormat = CSVFormat.valueOf("TDF");
        assertNotNull(tdfFormat);
        assertEquals(CSVFormat.TDF.getDelimiter(), tdfFormat.getDelimiter());
    }

    @Test
    void testValueOf_invalidFormat() {
        // Test that an invalid format string throws IllegalArgumentException
        assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf("InvalidFormatName"));
    }

    @Test
    void testValueOf_nullFormat() {
        // Test that null format string throws NullPointerException
        assertThrows(NullPointerException.class, () -> CSVFormat.valueOf(null));
    }
}
